import React, { useRef } from "react";
import { TreeView as Tree, type TreeRef } from "@lmb/kitsconcertomobile";
import { Flex, Text } from "../../../";
import type { ITreeViewProps } from "@lmb/kitsconcerto-types";
import { useTreeViewController } from "./useTreeViewController";
import TreeViewToolbar from "./Toolbar";
import { Pressable, View } from "react-native";
import {useKitsTheme} from "../../../Contexts/Theme";

const TreeView = <T = any,>(props: ITreeViewProps<T>) => {
    const {
        treeValue,
        selectedNode,
        filterValue,
        build,
        setFilterValue,
        expandAll,
        collapseAll,
        operations,
        treeProps,
    } = useTreeViewController(props);

    const {resolveToken} = useKitsTheme();
    const selectedBg = resolveToken('surface-hover');

    const {
        nodeTemplate,
        containerProps,
        hideSearchBox,
        hideDisabledButton,
        expendableControls,
        hideToolbar: propsHideToolbar,
    } = props;

    const treeRef = useRef<TreeRef>(null);

    const shouldHideToolbar =
        propsHideToolbar ||
        (!!hideSearchBox && !!hideDisabledButton && !expendableControls);

    return (
        <Flex
            id={"tree-view"}
            w={"full"}
            h={"full"}
            flexDirection={"column"}
            {...containerProps}
        >
            {!shouldHideToolbar && (
                <TreeViewToolbar
                    props={props}
                    filterValue={filterValue}
                    setFilterValue={setFilterValue}
                    treeRef={treeRef.current}
                    selectedNode={selectedNode}
                    expandAll={expandAll}
                    collapseAll={collapseAll}
                    onAddNode={operations.onAddNode}
                    onAddNodeItem={operations.onAddNodeItem}
                    onDeleteNode={operations.onDeleteNode}
                    onEditNode={operations.onEditNode}
                    build={build}
                />
            )}

            <Tree
                ref={treeRef}
                {...treeProps}
                filterValue={filterValue}
                filterMode={"lenient"}
                nodeTemplate={(node, options) => {
                    const isSelected = node.key == selectedNode?.key;
                    return (
                        <Pressable
                            onPress={() => {
                                if (treeProps.onNodeClick) {
                                    treeProps.onNodeClick({
                                        node,
                                        originalEvent: {} as any,
                                    });
                                }
                            }}
                            style={{
                                flex: 1,
                                flexDirection: "row",
                                alignItems: "center",
                                minHeight: 40,
                                paddingHorizontal: 4,
                                backgroundColor: isSelected
                                    ? selectedBg
                                    : "transparent",
                                borderRadius: 4,
                            }}
                        >
                            {!!nodeTemplate ? (
                                nodeTemplate(node, options)
                            ) : (
                                <Text
                                    fontWeight={isSelected ? "bold" : "normal"}
                                >
                                    {node.label}
                                </Text>
                            )}
                        </Pressable>
                    );
                }}
            />
        </Flex>
    );
};

export default TreeView;
